import{_ as e,o as a,c as o,ag as n}from"./chunks/framework.C9sp7nFj.js";const r="/screenshots/attendance-calendar.jpeg",p=JSON.parse('{"title":"Attendance calendar","description":"","frontmatter":{},"headers":[],"relativePath":"guide/attendance.md","filePath":"guide/attendance.md","lastUpdated":1776630283000}'),s={name:"guide/attendance.md"};function i(l,t,d,h,c,u){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="attendance-calendar" tabindex="-1">Attendance calendar <a class="header-anchor" href="#attendance-calendar" aria-label="Permalink to &quot;Attendance calendar&quot;">​</a></h1><p>A month-by-month view of your attendance, leave, and holidays.</p><h2 id="opening-it" tabindex="-1">Opening it <a class="header-anchor" href="#opening-it" aria-label="Permalink to &quot;Opening it&quot;">​</a></h2><p>Tap the <strong>Attendance</strong> tab at the bottom of the screen.</p><figure class="screenshot"><img src="'+r+'" alt="Attendance calendar for April 2026"><figcaption>Attendance tab — colour-coded month grid with Present / Absent / On Leave counts and total hours worked.</figcaption></figure><h2 id="what-you-see" tabindex="-1">What you see <a class="header-anchor" href="#what-you-see" aria-label="Permalink to &quot;What you see&quot;">​</a></h2><p>The month grid shows one cell per day of the current month. Each cell is colour-coded based on your status that day.</p><table tabindex="0"><thead><tr><th>Colour</th><th>Meaning</th></tr></thead><tbody><tr><td>🟢 <strong>Green</strong></td><td>Present — you had at least one IN/OUT pair</td></tr><tr><td>🔴 <strong>Red</strong></td><td>Absent — no check-ins recorded that day</td></tr><tr><td>🟡 <strong>Yellow</strong></td><td>Half Day</td></tr><tr><td>🔵 <strong>Blue</strong></td><td>On Leave — approved leave covered that day</td></tr><tr><td>⚪ <strong>Grey</strong></td><td>Holiday — per your holiday list</td></tr><tr><td>⚪ <strong>Light</strong></td><td>Weekend</td></tr></tbody></table><p>Below the grid is a <strong>summary row</strong> with:</p><ul><li><strong>Present</strong> — count of present days this month</li><li><strong>Absent</strong> — count of absent days</li><li><strong>On Leave</strong> — count of leave days</li><li><strong>Hours</strong> — total hours worked this month</li></ul><h2 id="changing-month" tabindex="-1">Changing month <a class="header-anchor" href="#changing-month" aria-label="Permalink to &quot;Changing month&quot;">​</a></h2><p>Top of the screen: <strong><code>‹ 2026 / 04 ›</code></strong></p><ul><li>Tap <strong>‹</strong> to go to the previous month</li><li>Tap <strong>›</strong> to go to the next month</li><li>The current month is shown in the middle</li></ul><h2 id="tap-a-day-for-details" tabindex="-1">Tap a day for details <a class="header-anchor" href="#tap-a-day-for-details" aria-label="Permalink to &quot;Tap a day for details&quot;">​</a></h2><p>Tap any coloured cell to open a bottom sheet showing:</p><ul><li><strong>Status</strong> — same as the colour (Present / Absent / …)</li><li><strong>Hours worked</strong> — to 2 decimals</li><li><strong>IN / OUT pairs</strong> — each pair with: <ul><li>Time in</li><li>Time out</li><li>Task (or &quot;No task&quot;)</li><li>Note: &quot;auto-closed at midnight&quot; if you forgot to check out</li></ul></li></ul><h3 id="the-auto-close-rule" tabindex="-1">The auto-close rule <a class="header-anchor" href="#the-auto-close-rule" aria-label="Permalink to &quot;The auto-close rule&quot;">​</a></h3><p>If you check in but forget to check out by midnight, the app automatically closes the pair at 23:59 of the same day. This is marked clearly in the detail sheet so it doesn&#39;t silently inflate your hours.</p><h2 id="times-are-in-your-phone-s-timezone" tabindex="-1">Times are in your phone&#39;s timezone <a class="header-anchor" href="#times-are-in-your-phone-s-timezone" aria-label="Permalink to &quot;Times are in your phone&#39;s timezone&quot;">​</a></h2><p>All times shown (IN / OUT on attendance days, check-in history, etc) are rendered in <strong>your phone&#39;s local timezone</strong>. If you travel — for example, phone in Riyadh (UTC+3) checking in against a company site in Muscat (UTC+4) — you&#39;ll see Riyadh-local times on the phone, and HR will see Muscat-local times in the ERP. Both represent the same real moment.</p><h2 id="skeleton-loading" tabindex="-1">Skeleton loading <a class="header-anchor" href="#skeleton-loading" aria-label="Permalink to &quot;Skeleton loading&quot;">​</a></h2><p>When you open the tab for the first time in a session, you&#39;ll see a <strong>pulsing grey grid</strong> for a second or two while the month data loads. Once the data arrives, the real colours fill in.</p><h2 id="what-counts-as-present" tabindex="-1">What counts as &quot;Present&quot; <a class="header-anchor" href="#what-counts-as-present" aria-label="Permalink to &quot;What counts as &quot;Present&quot;&quot;">​</a></h2><p>A day is <strong>Present</strong> if:</p><ul><li>You have at least one IN / OUT pair recorded</li><li>OR an Attendance row exists on that date with status = Present (e.g. created by HR)</li></ul><p>What counts as <strong>Absent</strong>:</p><ul><li>No check-ins AND no Attendance row for that date</li><li>AND the date is in the past</li></ul><p>Future days with no data show as blank (neither green nor red).</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/check-in">Check-in &amp; Check-out</a></li><li><a href="/guide/leave">Apply for leave</a></li></ul>',30)])])}const m=e(s,[["render",i]]);export{p as __pageData,m as default};
